import { randomUUID } from "crypto";
import type {
  User,
  InsertUser,
  Course,
  InsertCourse,
  Exercise,
  InsertExercise,
  Question,
  InsertQuestion,
  StudentResponse,
  InsertStudentResponse,
  StudentProgress,
  StudentBadge,
  Assignment,
  InviteCode,
  StudentDocument,
  InsertStudentDocument,
  Message,
  InsertMessage,
  Notification,
  InsertNotification,
  StudentGroup,
  InsertStudentGroup,
  GroupMember,
} from "@shared/schema";

export interface IStorage {
  // Users
  getUser(id: string): Promise<User | undefined>;
  getUserByUsername(username: string): Promise<User | undefined>;
  createUser(user: InsertUser): Promise<User>;

  // Courses
  getCourse(id: string): Promise<Course | undefined>;
  getAllCourses(): Promise<Course[]>;
  createCourse(course: InsertCourse): Promise<Course>;

  // Exercises
  getExercise(id: string): Promise<Exercise | undefined>;
  getExercisesByCourse(courseId: string): Promise<Exercise[]>;
  getAllExercises(): Promise<Exercise[]>;
  createExercise(exercise: InsertExercise): Promise<Exercise>;

  // Questions
  getQuestion(id: string): Promise<Question | undefined>;
  getQuestionsByExercise(exerciseId: string): Promise<Question[]>;
  createQuestion(question: InsertQuestion): Promise<Question>;

  // Student Responses
  createResponse(response: InsertStudentResponse): Promise<StudentResponse>;
  getResponsesByStudent(studentId: string): Promise<StudentResponse[]>;
  getResponsesByQuestion(questionId: string): Promise<StudentResponse[]>;
  updateResponseComment(id: string, comment: string): Promise<StudentResponse | undefined>;
  updateResponseGrade(id: string, isCorrect: boolean, comment?: string): Promise<StudentResponse | undefined>;

  // Student Progress
  getProgress(studentId: string, courseId: string): Promise<StudentProgress | undefined>;
  updateProgress(
    studentId: string,
    courseId: string,
    progressPercentage: number,
    correctAnswers?: number,
    totalQuestions?: number,
    completed?: boolean
  ): Promise<StudentProgress>;
  getAllStudentProgress(studentId: string): Promise<StudentProgress[]>;

  // Badges
  getBadgesByStudent(studentId: string): Promise<StudentBadge[]>;
  createBadge(badge: Omit<StudentBadge, "id">): Promise<StudentBadge>;

  // Assignments
  getAssignmentsByStudent(studentId: string): Promise<Assignment[]>;
  getAssignmentsByTeacher(teacherId: string): Promise<Assignment[]>;
  getAssignmentsByCourse(courseId: string): Promise<Assignment[]>;
  createAssignment(assignment: Omit<Assignment, "id">): Promise<Assignment>;
  deleteAssignment(assignmentId: string): Promise<void>;

  // Teacher queries
  getStudentsByTeacher(teacherId: string): Promise<(User & { progressPercentage: number })[]>;
  getStudentReports(teacherId: string): Promise<any[]>;

  // Admin
  getAllUsers(): Promise<User[]>;
  deleteUser(id: string): Promise<void>;
  getAllInviteCodes(): Promise<InviteCode[]>;
  getInviteCode(code: string): Promise<InviteCode | undefined>;
  createInviteCode(data: { code: string; label?: string | null }): Promise<InviteCode>;
  useInviteCode(code: string, userId: string): Promise<void>;
  deleteInviteCode(id: string): Promise<void>;

  // Student Documents
  getDocument(id: string): Promise<StudentDocument | undefined>;
  getDocumentsByStudent(studentId: string): Promise<StudentDocument[]>;
  getDocumentsByTeacher(teacherId: string): Promise<StudentDocument[]>;
  createDocument(doc: InsertStudentDocument): Promise<StudentDocument>;
  updateDocumentComment(id: string, comment: string, reviewed: boolean): Promise<StudentDocument | undefined>;
  deleteDocument(id: string): Promise<void>;

  // Messages
  getMessages(userId1: string, userId2: string): Promise<Message[]>;
  sendMessage(msg: InsertMessage): Promise<Message>;
  markMessagesRead(receiverId: string, senderId: string): Promise<void>;
  getUnreadCount(userId: string): Promise<number>;

  // Notifications
  getNotifications(userId: string): Promise<Notification[]>;
  createNotification(notif: InsertNotification): Promise<Notification>;
  markNotificationRead(id: string): Promise<void>;
  markAllNotificationsRead(userId: string): Promise<void>;
  getUnreadNotificationCount(userId: string): Promise<number>;
  // Groupes d'élèves
  getGroupsByTeacher(teacherId: string): Promise<StudentGroup[]>;
  createGroup(group: InsertStudentGroup): Promise<StudentGroup>;
  updateGroup(id: string, name: string, description: string, color: string): Promise<StudentGroup | undefined>;
  deleteGroup(id: string): Promise<void>;
  getGroupMembers(groupId: string): Promise<GroupMember[]>;
  addGroupMember(groupId: string, studentId: string): Promise<GroupMember>;
  removeGroupMember(groupId: string, studentId: string): Promise<void>;
  getStudentGroups(studentId: string): Promise<StudentGroup[]>;
}

